    # ------------ TRAINING LOGIC (unchanged) ------------
    def modifier_exo_par_mois(exo, mois):
        def rep_mod(match):
            series_str, reps_str = match.groups()
            series = int(series_str)
            base = int(reps_str.split("-")[0]) if "-" in reps_str else int(reps_str)
            
            # Application d'une fourchette stricte de 4 répétitions (Ex: 8 à 12, ou 5 à 9)
            if mois == 1: 
                start = base
                end = start + 4
            elif mois == 2: 
                start = max(1, base - 2)
                end = start + 4
            elif mois == 3: 
                series += 1 
                start = max(1, base - 4)
                end = start + 4
            else: 
                start = max(1, base - 2)
                end = start + 4
                return f"{series} séries de {start} à {end} (+ échec musculaire)"
            
            return f"{series} séries de {start} à {end}"
        
        return re.sub(r'(\d+) x (\d+(?:-\d+)?)', rep_mod, exo)

    def get_exercices_base(force_r, app_r, card_r, day_type):
        exos = []
        if day_type == "Full Body":
            if force_r > 6: exos.extend(["**Squat Barbell** : 5 x 5 reps (Repos: 3 min)", "**Développé couché** : 4 x 5 reps (Repos: 3 min)", "**Rowing buste penché** : 4 x 8 reps"])
            else: exos.extend(["**Presse à cuisses ou Goblet Squat** : 4 x 12 reps", "**Développé incliné haltères** : 3 x 12 reps", "**Tirage poitrine poulie** : 3 x 12 reps"])
            if app_r > 5: exos.extend(["**Élévations latérales** : 3 x 15 reps", "**Curl biceps + Extension triceps** (Superset) : 3 x 12 reps"])
            if card_r > 6: exos.append("**Finisher Cardio** : 10 min de Rameur ou Corde à sauter")
        elif day_type == "Push":
            if force_r > 6: exos.append("**Développé Couché lourd** : 4 x 5 reps (Repos: 4 min)")
            else: exos.append("**Développé Couché (Haltères)** : 4 x 10 reps")
            exos.extend(["**Développé Militaire assis** : 3 x 10 reps", "**Dips ou Écartés vis-à-vis** : 3 x 12 reps", "**Élévations latérales** : 4 x 15 reps", "**Extensions Triceps corde** : 3 x 15 reps"])
        elif day_type == "Pull":
            if force_r > 6: exos.append("**Soulevé de terre (Deadlift)** : 3 x 5 reps (Repos: 4 min)")
            else: exos.append("**Tirage vertical large** : 4 x 10 reps")
            exos.extend(["**Rowing un bras haltère** : 3 x 10 reps", "**Oiseau (Arrière d'épaules)** : 4 x 15 reps", "**Curl Biceps** : 4 x 12 reps", "**Gainage planche** : 3 x 60 s"])
        elif day_type == "Legs":
            if force_r > 6: exos.append("**Squat profond** : 4 x 5 reps (Repos: 3 min)")
            else: exos.append("**Presse à cuisses** : 4 x 12 reps")
            exos.extend(["**Fentes bulgares** : 3 x 12 reps", "**Leg Curl Ischio-jambiers** : 3 x 15 reps", "**Extensions mollets** : 4 x 20 reps"])
            if card_r > 6: exos.append("**Finisher** : 5 min sprints sur vélo (20s max / 40s lent)")
        elif day_type == "Cardio":
            exos.extend(["**Échauffement dynamique** : 5 minutes", "**HIIT** : 12x 30s effort MAX / 30s récupération", "**LISS** : 30 minutes de course légère", "**Retour au calme et étirements** : 10 minutes"])
        elif "Séance de Sport Principal" in day_type or "Cardio / Sport ciblé" in day_type:
            exos.extend(["**Préparation** : Échauffement articulaire, gammes et activation.", "**Votre pratique sportive** : Entraînement tactique/technique poussé pour votre discipline.", "**Préparation physique (PP)** : Renforcement prophylactique, cœur et appuis en fin de séance.", "**Récupération** : 10 minutes de retour au calme (auto-massages)."])
        elif "Séance Sport / Récupération" in day_type:
            exos.extend(["**Pratique sportive de haut niveau** : Déroulement de vos séances programmées.", "**Alerte Récupération** : Votre volume d'entraînement global est à un niveau quasi-professionnel. Écoutez votre système nerveux central et forcez un jour ou deux de REPOS COMPLET à la première baisse de performance inexpliquée."])
        elif "Repos actif" in day_type:
            exos.extend(["**Marche légère** : 30 à 45 minutes en extérieur (Zone cardio 1, très confortable)", "**Mobilité / Étirements** : 15 min de yoga doux ou routine de mobilité articulaire", "**Option ludique** : Natation légère, vélo à faible allure, ou autre sport récréatif sans forcer", "*Objectif* : Favoriser la circulation sanguine et la récupération sans fatiguer le système nerveux."])
        elif day_type == "Repos complet":
            exos.extend(["**Récupération totale** : Pas d'activité physique demandant un effort soutenu.", "**Soins spécifiques** : Auto-massages (rouleau), bains chauds/froids, sieste.", "*Objectif* : Réparer les fibres musculaires (le corps progresse pendant le repos !)."])
        return exos

    def generer_plan_entrainement(jours, niveau, scores, mois):
        force_r = scores["Force"]; app_r = scores["Apparence"]; card_r = scores["Cardio"]
        titres_mois = ["Phase 1 : Adaptation Anatomique (Technique & Volume)", "Phase 2 : Hypertrophie et Progression Linéaire", "Phase 3 : Intensification et Pic de Force", "Phase 4 : Techniques Avancées et Consolidation"]
        html = f"<div class='month-title'>{titres_mois[mois-1]}</div>"
        
        # Ajustement des entraînements pour inclure massivement du Cardio selon l'objectif (0 à 10)
        if jours == 1: 
            train = ["Cardio"] if card_r >= 8 else ["Full Body"]
            split = [train[0], "Repos actif", "Repos complet", "Repos actif", "Repos complet", "Repos actif", "Repos complet"]
        elif jours == 2: 
            train = ["Full Body", "Cardio"] if card_r >= 6 else ["Full Body", "Full Body"]
            split = [train[0], "Repos actif", "Repos complet", train[1], "Repos actif", "Repos complet", "Repos actif"]
        elif jours == 3: 
            if card_r >= 8: train = ["Full Body", "Cardio", "Cardio"]
            elif card_r >= 6: train = ["Full Body", "Full Body", "Cardio"]
            elif niveau >= 3: train = ["Push", "Pull", "Legs"]
            else: train = ["Full Body", "Full Body", "Full Body"]
            split = [train[0], "Repos actif", train[1], "Repos complet", train[2], "Repos actif", "Repos complet"]
        elif jours == 4: 
            if card_r >= 8: train = ["Push", "Pull", "Cardio", "Cardio"]
            elif card_r >= 6: train = ["Push", "Pull", "Legs", "Cardio"]
            else: train = ["Push", "Pull", "Legs", "Full Body"]
            split = [train[0], train[1], "Repos actif", train[2], train[3], "Repos complet", "Repos actif"]
        elif jours == 5: 
            if card_r >= 8: train = ["Push", "Pull", "Cardio", "Legs", "Cardio"]
            elif card_r >= 6: train = ["Push", "Pull", "Legs", "Push", "Cardio"]
            else: train = ["Push", "Pull", "Legs", "Push", "Pull"]
            split = [train[0], train[1], train[2], "Repos actif", train[3], train[4], "Repos complet"]
        elif jours == 6: 
            if card_r >= 8: train = ["Push", "Pull", "Cardio", "Legs", "Full Body", "Cardio"]
            elif card_r >= 6: train = ["Push", "Pull", "Legs", "Push", "Pull", "Cardio"]
            else: train = ["Push", "Pull", "Legs", "Push", "Pull", "Legs"]
            split = [train[0], train[1], train[2], train[3], train[4], train[5], "Repos actif"]
        else: # 7 jours
            if card_r >= 8: train = ["Push", "Pull", "Cardio", "Legs", "Cardio", "Full Body", "Cardio"]
            elif card_r >= 6: train = ["Push", "Pull", "Legs", "Push", "Pull", "Legs", "Cardio"]
            else: train = ["Push", "Pull", "Legs", "Push", "Pull", "Legs", "Full Body"]
            split = train

        sports = data.get("sports_pratiques", [])
        nv_sport = data.get("niveau_sport", "")
        
        for i, day_type in enumerate(split):
            if sports:
                if "Amateur" in nv_sport or "Intense" in nv_sport:
                    # Niveau compétitif/expert -> le sport "mange" le split traditionnel cardio et repos
                    if day_type == "Cardio" or day_type == "Repos actif":
                        day_type = f"Séance de Sport Principal ({', '.join(sports)})"
                    elif day_type == "Repos complet" and "Intense" in nv_sport:
                        day_type = f"Séance Sport / Récupération active ({', '.join(sports)})"
                else:
                    if day_type == "Cardio":
                        day_type = f"Cardio / Sport ciblé ({', '.join(sports)})"
                    elif day_type == "Repos actif":
                        day_type = f"Repos actif ou Pratique légère ({', '.join(sports)})"
                
            if "Repos" in day_type:
                html += f"<div class='day-box-rest'><h4>Jour {i+1} : {day_type}</h4><ul>"
            else:
                html += f"<div class='day-box'><h4>Jour {i+1} : {day_type}</h4><ul>"
                
            exos_base = get_exercices_base(force_r, app_r, card_r, day_type)
            for exo in exos_base:
                if "Cardio" not in day_type and "Repos" not in day_type and "Échauffement" not in exo and "Finisher" not in exo and "Gainage" not in exo:
                    exo = modifier_exo_par_mois(exo, mois)
                html += f"<li>{exo}</li>"
            html += "</ul></div>"
        return html

    # ------------ DIET LOGIC ------------
    def extraire_mot(choix, position):
        return choix.split()[0] # ex: "Méditerranéenne (Huile...)" -> "Méditerranéenne"

    def generer_recette(regime_base, p_g, g_g, l_g, cuisine, meal_name="Repas", allergies_list=None, used_templates=None, used_pro=None):
        """Génère une recette détaillée basée sur la cuisine, le type de repas, et calcule les portions en g"""
        if allergies_list is None: allergies_list = []
        if used_templates is None: used_templates = set()
        if used_pro is None: used_pro = set()
        
        # LOGIQUE SPÉCIFIQUE COLLATION (Snacks)
        if "Colla" in meal_name:
            q_skyr = int(p_g * 10)
            q_whey = int(p_g * 1.25)
            q_avoine = int(g_g * 1.6)
            q_fruit = int(g_g * 4)
            q_beurre_nuts = int(l_g * 2)
            q_galettes = max(1, int(g_g / 8)) # 1 galette de riz = ~8g glucides
            
            beurre_pool = ["beurre de cacahuète", "purée d'amandes", "purée de noix de cajou"]
            if "Arachides" in allergies_list: beurre_pool = [b for b in beurre_pool if "cacahuète" not in b]
            if "Fruits à coque" in allergies_list: beurre_pool = [b for b in beurre_pool if "amande" not in b and "cajou" not in b]
            if not beurre_pool: beurre_pool = ["graines de chia/lin", "beurre de tournesol"]
            beurre_option = random.choice(beurre_pool)

            fruit_option = random.choice(["banane", "pomme", "fruits rouges", "kiwi"])
            
            if "Vegan" in regime_base:
                colla_templates = [
                    f"**Smoothie Énergétique :** Mixez **{q_whey}g de protéines végétales**, **{q_fruit}g de {fruit_option}**, **{q_avoine}g de flocons d'avoine** et **{q_beurre_nuts}g de {beurre_option}** avec du lait végétal ou de l'eau.",
                    f"**Galettes de riz gourmandes :** **{q_galettes} galettes de riz soufflé**, tartinées avec **{q_beurre_nuts}g de {beurre_option}**. Accompagnées d'un shaker de **{q_whey}g de protéines** et **{q_fruit}g de {fruit_option}**.",
                    f"**Pudding de Chia/Avoine (Overnight) :** Laissez reposer **{q_avoine}g de flocons d'avoine** dans du lait végétal avec **{q_whey}g de protéines végétales**. Garnissez de **{q_beurre_nuts}g de {beurre_option}** et **{q_fruit}g de {fruit_option}**."
                ]
            else:
                colla_templates = [
                    f"**Smoothie Post-Effort :** Mixez **{q_whey}g de Whey protéine**, **{q_fruit}g de {fruit_option}**, **{q_avoine}g de flocons d'avoine** et **{q_beurre_nuts}g de {beurre_option}** avec du lait ou de l'eau.",
                    f"**Bowl express Skyr/Fruits :** **{q_skyr}g de Skyr ou fromage blanc**, mélangé avec **{q_fruit}g de {fruit_option}** et **{q_beurre_nuts}g de {beurre_option}**. Accompagné de **{q_galettes} galettes de riz soufflé** (ou flocons d'avoine équivalents).",
                    f"**Collation Solide (Tartines/Galettes) :** **{q_galettes} galettes de riz** (ou pain complet équivalent), nappées de **{q_beurre_nuts}g de {beurre_option}**. Buvez avec un shaker de **{q_whey}g de Whey** et croquez **{q_fruit}g de {fruit_option}**.",
                    f"**Crème dessert protéinée :** Battez fermement **{q_skyr}g de fromage blanc nature** avec **{q_avoine}g d'avoine mixée** et une touche de poudre de cacao 100% sans sucre. Ajoutez **{q_beurre_nuts}g de {beurre_option}** et **{q_fruit}g de {fruit_option}**."
                ]
                
            if "Gluten" in allergies_list: colla_templates = [t.replace("flocons", "flocons de sarrasin").replace("pain complet", "pain sans gluten") for t in colla_templates]
            if "Lactose" in allergies_list: colla_templates = [t.replace("Skyr ou fromage blanc", "Yaourt de Soja/Coco nature").replace("fromage blanc nature", "soja onctueux").replace("Whey protéine", "Protéine végétale").replace("Whey", "Protéine sans lait") for t in colla_templates]

            if not colla_templates: return "Collation standard (Source protéinée rapide + Fruit sec)"
            
            attempts = 0
            desc = random.choice(colla_templates)
            while any(desc[:30] == t[:30] for t in used_templates) and attempts < 10:
                desc = random.choice(colla_templates)
                attempts += 1
            used_templates.add(desc)
            return desc

        # LOGIQUE SPÉCIFIQUE AU MATIN (Petit-Déjeuner)
        if "Petit" in meal_name:
            nb_oeufs = max(2, int(p_g / 6))
            q_jambon = int(p_g * 5)
            q_skyr = int(p_g * 10)
            q_whey = int(p_g * 1.25)
            
            q_avoine = int(g_g * 1.6)
            q_pain = int(g_g * 2)
            q_cereales = int(g_g * 1.3)
            q_fruit = int(g_g * 4)
            q_beurre_nuts = int(l_g * 2)
            
            beurre_pool = ["beurre de cacahuète", "purée d'amandes", "cerneaux de noix"]
            if "Arachides" in allergies_list: beurre_pool = [b for b in beurre_pool if "cacahuète" not in b]
            if "Fruits à coque" in allergies_list: beurre_pool = [b for b in beurre_pool if "amande" not in b and "noix" not in b]
            if not beurre_pool: beurre_pool = ["graines de chia/lin", "huile de coco légère"]
            beurre_option = random.choice(beurre_pool)

            fruit_option = random.choice(["banane en rondelles", "pomme en morceaux", "fruits rouges", "kiwi"])
            
            if "Vegan" in regime_base:
                pt_templates = [
                    f"**Bowl Protéiné :** **{q_skyr}g de yaourt végétal (soja/coco)**, mélangé avec **{q_avoine}g de flocons d'avoine**, **{q_fruit}g de {fruit_option}**, et **{q_beurre_nuts}g de {beurre_option}**.",
                    f"**Tartines Énergétiques :** **{q_pain}g de pain complet ou intégral**, tartiné avec **{q_beurre_nuts}g de {beurre_option}**. Accompagné d'un shaker de **{q_whey}g de protéines végétales** et de **{q_fruit}g de {fruit_option}**.",
                    f"**Pancakes vegans express :** Pâte à base de **{q_avoine}g d'avoine** mixée avec **{q_whey}g de protéine végétale**, et de l'eau. Cuire et napper avec vos **{q_beurre_nuts}g de {beurre_option}**."
                ]
            elif "Végétarien" in regime_base or "Pesco" in regime_base:
                pt_templates = [
                    f"**Bowl Flocons & Fromage blanc :** **{q_skyr}g de Skyr ou fromage blanc 0%**, mélangé avec **{q_avoine}g de flocons d'avoine**, **{q_fruit}g de {fruit_option}**, et **{q_beurre_nuts}g de {beurre_option}**.",
                    f"**Le Classique Œufs :** **{nb_oeufs} œufs entiers** (brouillés ou au plat) avec légumes, servis avec **{q_pain}g de pain complet/levain**. En dessert : **{q_fruit}g de {fruit_option}**.",
                    f"**Tartines Énergétiques :** **{q_pain}g de pain intégral**, tartiné avec **{q_beurre_nuts}g de {beurre_option}**. Accompagné d'un shaker de **{q_whey}g de Whey protéine**."
                ]
            else:
                pt_templates = [
                    f"**Le Salé (Œufs & Jambon) :** **{nb_oeufs - 1} œufs entiers** brouillés avec **{int(q_jambon*0.4)}g de jambon blanc ou bacon de dinde** et des légumes (tomates/épinards). Accompagné de **{q_pain}g de pain au levain/complet**.",
                    f"**Oatmeal & Protéines :** **{q_avoine}g de flocons d'avoine** (cuits lait/eau), mélangés avec **{q_whey}g de protéine en poudre (Whey)**. Garnissez avec **{q_beurre_nuts}g de {beurre_option}** et **{q_fruit}g de {fruit_option}**.",
                    f"**Bowl Skyr / Fruits :** **{q_skyr}g de Skyr ou de yaourt grec**, saupoudré de cannelle, **{q_cereales}g de flocons/muesli**, et **{q_beurre_nuts}g de noix/amandes concassées**."
                ]
            if "Œufs" in allergies_list: pt_templates = [t for t in pt_templates if "œufs" not in t.lower() and "Œufs" not in t]
            if "Gluten" in allergies_list: pt_templates = [t.replace("pain", "pain sans gluten").replace("flocons", "flocons de sarrasin") for t in pt_templates]
            if "Lactose" in allergies_list: pt_templates = [t.replace("Skyr ou fromage blanc 0%", "Yaourt de Soja/Coco nature").replace("Whey protéine", "Protéine végétale") for t in pt_templates]

            if not pt_templates: return "Petit déjeuner standard ajusté selon vos besoins"
            
            attempts = 0
            desc = random.choice(pt_templates)
            while any(desc[:30] == t[:30] for t in used_templates) and attempts < 10:
                desc = random.choice(pt_templates)
                attempts += 1
            used_templates.add(desc)
            return desc

        # Formules basiques de conversion
        pro_qty = int(p_g * 4.5)
        glu_qty_sec = int(g_g * 1.35)
        glu_qty_humide = int(g_g * 5)
        lipides_add = max(0, int(l_g - (pro_qty*0.02) - (glu_qty_sec*0.01)))
        huile_cas = max(1, math.ceil(lipides_add / 10))

        pro_pool = []
        if "Vegan" in regime_base:
            pro_pool = ["Tofu ferme", "Tempeh grillé", "Seitan", "Protéines de soja texturées (PST)"]
        elif "Pesco" in regime_base:
            pro_pool = ["Filet de saumon", "Filet de cabillaud", "Crevettes décortiquées", "Miettes de thon", "Tofu"]
        elif "Végétarien" in regime_base:
            pro_pool = ["Œufs entiers (x3) et blancs d'œufs", "Tofu bio", "Fromage blanc 0% et isolat"]
        else: # Omnivore
            pro_pool = ["Blanc de poulet", "Viande hachée à 5%", "Dinde grillée", "Poisson blanc", "Émincé de bœuf", "Filet de saumon"]

        # Filtrage Allergies stricts
        if "Soja" in allergies_list: pro_pool = [p for p in pro_pool if "Tofu" not in p and "Tempeh" not in p and "soja" not in p]
        if "Œufs" in allergies_list: pro_pool = [p for p in pro_pool if "Œufs" not in p]
        if "Poissons" in allergies_list or "Crustacés" in allergies_list: pro_pool = [p for p in pro_pool if "Saumon" not in p and "Cabillaud" not in p and "thon" not in p and "Poisson" not in p and "Crevettes" not in p]
        if "Lactose" in allergies_list: pro_pool = [p for p in pro_pool if "Fromage" not in p and "isolat" not in p]
        if "Gluten" in allergies_list: pro_pool = [p for p in pro_pool if "Seitan" not in p]

        if not pro_pool: pro_pool = ["Source de protéine isolée adaptée"]
        
        # Anti-répétition des protéines
        dispo_pro = [p for p in pro_pool if p not in used_pro]
        if not dispo_pro: dispo_pro = pro_pool # reset
        src_pro = random.choice(dispo_pro)
        used_pro.add(src_pro)

        # Adaptation selon la Cuisine
        cuisine_type = extraire_mot(cuisine, 0)
        
        if cuisine_type == "Méditerranéenne":
            templates = [
                f"**{src_pro} ({pro_qty}g)** grillé aux herbes de Provence, accompagné de **{glu_qty_sec}g (poids cru) de pâtes complètes ou boulgour**, le tout avec **{huile_cas} C.à.S d'huile d'olive**, courgettes et tomates rôties.",
                f"**{src_pro} ({pro_qty}g)** en papillote au citron et thym, servi avec **{glu_qty_sec}g (poids cru) de quinoa**, accompagné d'une salade grecque (concombres, tomates, oignons rouges) arrosée de **{huile_cas} C.à.S d'huile d'olive extra vierge**.",
                f"Poêlée de **{src_pro} ({pro_qty}g)** à l'ail et à l'origan, avec **{int(glu_qty_humide*0.8)}g de pommes de terre grenailles au four**, des poivrons grillés et une portion de tapenade d'olives noires (apportant vos **{lipides_add}g de lipides**)."
            ]
        elif cuisine_type == "Asiatique":
            templates = [
                f"Wok sauté sauce soja allégée en sel avec **{src_pro} ({pro_qty}g)**, sur une base de **{glu_qty_sec}g de riz basmati cru ou nouilles Soba**, avec **{huile_cas} C.à.S d'huile de sésame**, de l'ail, gingembre frais et bok choy.",
                f"Bol type Poke/Donburi : **{src_pro} ({pro_qty}g)** glacé sauce teriyaki maison, **{glu_qty_sec}g de riz à sushi (poids cru)**, avocat (**{lipides_add}g de lipides**), edamame, et algues nori.",
                f"Soupe Pho ou Ramen express : Bouillon clair épicé, **{src_pro} ({pro_qty}g)** finement tranché, **{glu_qty_sec}g de vermicelles de riz (pesés crus)**, coriandre, citron vert et **{huile_cas} C.à.S d'huile de cacahuète/sésame**."
            ]
        elif cuisine_type == "Latino/Mexicaine":
            templates = [
                f"Bol façon Fajitas : **{src_pro} ({pro_qty}g)** aux épices cajun ou fajita, **{int(glu_qty_sec*0.8)}g de riz cru** et une portion de haricots noirs. Ajoutez du Guacamole (**{lipides_add}g de lipides**), des poivrons rouges et du citron vert.",
                f"Tacos Sains : 3 à 4 petites tortillas de maïs (équivalent **{glu_qty_sec}g glucides crus**), **{src_pro} ({pro_qty}g)** sauté aux oignons, salsa roja, coriandre fraîche et **{huile_cas} C.à.S d'huile d'olive** pour la cuisson.",
                f"Chili express protéiné : **{src_pro} ({pro_qty}g)** mijoté avec des dés de tomates, maïs et haricots rouges (totalisant **{glu_qty_sec}g de glucides équivalents crus**), servi avec une cuillère de crème fraîche entière ou de cheddar (**{lipides_add}g de lipides**)."
            ]
        elif cuisine_type == "Moyen-Orient":
            templates = [
                f"Assiette orientale levantine : **{src_pro} ({pro_qty}g)** mariné au cumin et paprika, avec **{glu_qty_sec}g de couscous ou quinoa cru**, accompagné d'une sauce Tahini (équivalente à **{lipides_add}g de lipides**), et carottes fondantes.",
                f"Salade Taboulé revisitée : **{src_pro} ({pro_qty}g)** grillé, boulgour persillé (**{glu_qty_sec}g cru**), feuilles de menthe, concombres, grenade, et **{huile_cas} C.à.S d'huile d'olive / citron**.",
                f"Bol Houmous & Rôti : **{src_pro} ({pro_qty}g)** enrobé d'épices Zaatar, patates douces rôties (environ **{glu_qty_humide}g**), et une belle portion de houmous maison ou de purée de sésame (**{lipides_add}g de lipides**)."
            ]
        elif cuisine_type == "Américaine":
            templates = [
                f"Burger Fit ou Barbecue Plate : **{src_pro} ({pro_qty}g)** grillé, avec **{glu_qty_humide}g de frites de patates douces au four**, sauce moutarde miel (light), et **{lipides_add}g de beurre de cacahuète/amande** (en dessert ou dans une sauce).",
                f"Steakhouse Diner (Low Fat) : **{src_pro} ({pro_qty}g)** cuisson saisie, purée de pommes de terre maison (**{glu_qty_humide}g**), généreuse portion de haricots verts sautés dans **{huile_cas} C.à.S de beurre ou d'huile**.",
                f"Mac & Cheese Revisité : **{src_pro} ({pro_qty}g)** mélangé avec **{glu_qty_sec}g de macaronis (cru)**, sauce onctueuse à base de courge butternut mixée avec une petite portion de cheddar corsé fondu (**{lipides_add}g de lipides**)."
            ]
        else:
            templates = [
                f"Repas équilibré standard : **{pro_qty}g de {src_pro}**, peser **{glu_qty_sec}g de riz, pâtes ou avoine (avant cuisson)**, mélanger avec **{huile_cas} C.à.S de votre huile préférée**, et une grosse portion de légumes verts de saison.",
                f"Salade composée massive : **{pro_qty}g de {src_pro}** froid, immense base de verdure, **{glu_qty_sec}g de pâtes froides ou de riz cru**, tomates cerises, et une vinaigrette contenant **{huile_cas} C.à.S d'huile**.",
                f"Sauté tout-en-un (One Pot) : **{pro_qty}g de {src_pro}** coupé en dés, sauté avec **{glu_qty_sec}g de céréales** et un mix de légumes de saison, cuit avec **{huile_cas} C.à.S d'huile saine**."
            ]
            
